from __future__ import annotations

from datetime import datetime, timezone

from django import forms
from django.core.exceptions import ValidationError


class TimestampField(forms.Field):
    def to_python(self, value: str | None) -> datetime | None:
        if value is None:
            return None

        try:
            value_int = int(value)
        except ValueError:
            raise ValidationError(message="Must be an integer")

        # 10000000000 is year 2286 (a sanity check)
        if value_int < 0 or value_int > 10000000000:
            raise ValidationError(message="Out of bounds")

        return datetime.fromtimestamp(value_int, timezone.utc)


class FlipsFiltersForm(forms.Form):
    start = TimestampField(required=False)
    end = TimestampField(required=False)
    seconds = forms.IntegerField(required=False, min_value=0, max_value=31536000)

import json

from django.http import HttpResponseBadRequest, JsonResponse
from django.views import View

from wagtail.users.models import UserProfile


class DismissiblesView(View):
    def get(self, request, *args, **kwargs):
        # The UserProfile may not exist for the user, in which case return an empty object
        profile = getattr(request.user, "wagtail_userprofile", None)
        dismissibles = profile.dismissibles if profile else {}
        return JsonResponse(dismissibles)

    def patch(self, request, *args, **kwargs):
        try:
            updates = json.loads(request.body)
        except json.JSONDecodeError:
            return HttpResponseBadRequest()

        # Make sure the UserProfile exists
        profile = UserProfile.get_for_user(request.user)
        profile.dismissibles.update(updates)
        profile.save(update_fields=["dismissibles"])
        return JsonResponse(profile.dismissibles)

