class EventSubscriptionManager(models.Manager):
    def create_for(self, stored_event_type, user):
        return self.create(
            stored_event_type=stored_event_type, user=user
        )

    def get_for(self, stored_event_type, user):
        return self.filter(
            stored_event_type=stored_event_type, user=user
